# ✅ Problem must have optimal substructure
# Example: Dijkstra's shortest path (greedy works)
graph = {
    'A': {'B': 1, 'C': 4},
    'B': {'C': 2, 'D': 5},
    'C': {'D': 1},
    'D': {}
}

def dijkstra(graph, start):
    distances = {node: float('inf') for node in graph}
    distances[start] = 0
    unvisited = list(graph.keys())

    while unvisited:
        # ✅ Greedy: Pick closest unvisited node
        current = min(unvisited, key=lambda x: distances[x])  # ✅ Greedy choice [web:198]
        unvisited.remove(current)

        for neighbor, weight in graph[current].items():
            # ✅ Update distance if shorter path found
            distances[neighbor] = min(distances[neighbor], distances[current] + weight)

    return distances

dijkstra(graph, 'A')  # ✅ {'A': 0, 'B': 1, 'C': 3, 'D': 4} (optimal) [web:198]
